import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"アップロードチャンネル設定","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/index.md","filePath":"ja-JP/upload/index.md","lastUpdated":1781962217000}'),i={name:"ja-JP/upload/index.md"};function o(l,t,s,n,h,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="アップロードチャンネル設定" tabindex="-1">アップロードチャンネル設定 <a class="header-anchor" href="#アップロードチャンネル設定" aria-label="Permalink to &quot;アップロードチャンネル設定&quot;">​</a></h1><p>ImgBed では、複数の保存先を「チャンネル」として追加できます。画像、動画、音声、その他ファイルをどこへ保存するかは、アップロードチャンネルで管理します。</p><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; アップロード設定</span></span></code></pre></div><p>ここから新しいチャンネルを追加し、有効化、容量制限、備考、接続確認などを行います。</p><h2 id="このセクションで扱うチャンネル" tabindex="-1">このセクションで扱うチャンネル <a class="header-anchor" href="#このセクションで扱うチャンネル" aria-label="Permalink to &quot;このセクションで扱うチャンネル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>チャンネル</th><th>主な用途</th></tr></thead><tbody><tr><td>Cloudflare R2</td><td>Cloudflare 上のオブジェクトストレージ</td></tr><tr><td>S3</td><td>AWS S3、Backblaze B2、MinIO などの S3 互換ストレージ</td></tr><tr><td>Google Drive</td><td>Google アカウントの Drive に保存</td></tr><tr><td>OneDrive</td><td>Microsoft アカウントの OneDrive に保存</td></tr><tr><td>Dropbox</td><td>Dropbox アカウントに保存</td></tr><tr><td>pCloud</td><td>pCloud アカウントに保存</td></tr><tr><td>WebDAV</td><td>NAS、クラウドドライブ、対応ストレージに保存</td></tr><tr><td>Telegram</td><td>Telegram チャンネルを保存先として利用</td></tr><tr><td>Discord</td><td>Discord チャンネルを保存先として利用</td></tr><tr><td>GitHub Releases</td><td>GitHub Release Assets に保存</td></tr><tr><td>GitLab Packages</td><td>GitLab Generic Packages に保存</td></tr><tr><td>Hugging Face</td><td>Hugging Face Repository に保存</td></tr><tr><td>Yandex</td><td>Yandex Disk に保存</td></tr></tbody></table><h2 id="追加前に確認すること" tabindex="-1">追加前に確認すること <a class="header-anchor" href="#追加前に確認すること" aria-label="Permalink to &quot;追加前に確認すること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>確認項目</th><th>内容</th></tr></thead><tbody><tr><td>保存先アカウント</td><td>実際にファイルを保存するアカウントを用意します</td></tr><tr><td>API キー / Token</td><td>チャンネルごとに必要な認証情報を準備します</td></tr><tr><td>保存ディレクトリ</td><td>初期値は <code>imgbed</code> が多いですが、必要に応じて変更できます</td></tr><tr><td>容量制限</td><td>容量上限やしきい値を設定するか決めます</td></tr><tr><td>公開 URL</td><td>CDN や独自ドメインを使う場合は事前に確認します</td></tr></tbody></table><h2 id="追加後の確認" tabindex="-1">追加後の確認 <a class="header-anchor" href="#追加後の確認" aria-label="Permalink to &quot;追加後の確認&quot;">​</a></h2><ol><li>チャンネルカードが表示される。</li><li>チャンネルが有効になっている。</li><li>保存したキーやディレクトリが正しく表示される。</li><li>容量確認が必要な場合は実行する。</li><li>テスト画像をアップロードし、リンクが開けることを確認する。</li></ol><p>エラーが出る場合は、まず認証情報、保存先ディレクトリ、権限、API の利用制限を確認してください。</p>',12)])])}const u=d(i,[["render",o]]);export{b as __pageData,u as default};
